headerButton.customFunction:
// ═══════════════════════════════════════════════════════════════════
// Custom Action — Agregar Dispositivo v2
// Flujo: Escanear QR → Configuración → Datos → Crear → Resumen
// ═══════════════════════════════════════════════════════════════════

let $injector = widgetContext.$scope.$injector;
let customDialog = $injector.get(widgetContext.servicesMap.get('customDialog'));

const CS_URL       = 'https://chirpstack.nexoragro.com';
const CS_KEY       = 'TU_CS_API_KEY';
const CS_TENANT_ID = 'e35654cf-d46b-438c-afdb-1a10c769ea34';
const N8N_NODO_URL = 'https://backend.nexoragro.com/webhook/nexor/nodo';

// ── CS helpers ───────────────────────────────────────────────────────

function csRequest(method, path, body) {
  let opts = {
    method: method,
    headers: { 'Authorization': 'Bearer ' + CS_KEY, 'Content-Type': 'application/json' }
  };
  if (body !== undefined) opts.body = JSON.stringify(body);
  return fetch(CS_URL + path, opts).then(function(r) {
    if (!r.ok) return r.text().then(function(t) {
      let msg; try { msg = JSON.parse(t).message || t; } catch(e) { msg = t; }
      let err = new Error(msg); err.status = r.status; throw err;
    });
    return r.text().then(function(t) { return t ? JSON.parse(t) : null; });
  });
}
function csGet(path)        { return csRequest('GET',  path);       }
function csPost(path, body) { return csRequest('POST', path, body); }
function csDelete(path)     { return csRequest('DELETE', path);     }

// ── TB helpers ───────────────────────────────────────────────────────

function tbRequest(method, path, body) {
  let token = localStorage.getItem('jwt_token') || '';
  let opts = {
    method: method,
    headers: { 'Content-Type': 'application/json', 'X-Authorization': 'Bearer ' + token }
  };
  if (body !== undefined) opts.body = JSON.stringify(body);
  return fetch(path, opts).then(function(r) {
    if (!r.ok) return r.text().then(function(t) {
      let msg; try { msg = JSON.parse(t).message || t; } catch(e) { msg = t; }
      let err = new Error(msg); err.status = r.status; throw err;
    });
    return r.text().then(function(t) { return t ? JSON.parse(t) : null; });
  });
}
function tbGet(path)        { return tbRequest('GET',    path);        }
function tbPost(path, body) { return tbRequest('POST',   path, body);  }
function tbDelete(path)     { return tbRequest('DELETE', path);        }

// ── Parsear QR ───────────────────────────────────────────────────────

function parseQR(raw) {
  let s = (raw || '').trim();
  if (s.includes(';')) {
    let parts = s.split(';');
    return { type: 'caja', sn: parts[0] || '', eui: (parts[1] || '').toUpperCase(), appEui: (parts[2] || '').toUpperCase(), appKey: (parts[3] || '').toUpperCase() };
  }
  if (/^[0-9A-Fa-f]{16}$/.test(s)) {
    return { type: 'etiqueta', eui: s.toUpperCase() };
  }
  return { type: 'desconocido' };
}

// ── Generar nombre automático ────────────────────────────────────────

function generateDeviceName(modelo) {
  if (!modelo) return Promise.resolve('');
  return tbGet('/api/tenant/devices?pageSize=1000&page=0&textSearch=' + encodeURIComponent(modelo + '-'))
    .then(function(res) {
      let devices = (res && res.data) || [];
      let escaped = modelo.replace(/[-\/\\^$*+?.()|[\]{}]/g, '\\$&');
      let pattern = new RegExp('^' + escaped + '-(\\d+)$', 'i');
      let maxNum  = 0;
      devices.forEach(function(d) {
        let m = (d.name || '').match(pattern);
        if (m) { let n = parseInt(m[1], 10); if (n > maxNum) maxNum = n; }
      });
      return modelo + '-' + String(maxNum + 1).padStart(4, '0');
    })
    .catch(function() { return modelo + '-0001'; });
}

