            <mat-icon>error_outline</mat-icon><span>{{ appKeyError }}</span>
          </div>
        </div>

        <!-- JoinEUI opcional -->
        <mat-form-field>
          <mat-label>JoinEUI <span style="opacity:.6;font-size:11px">(opcional)</span></mat-label>
          <input matInput [(ngModel)]="joinEui" name="joinEui"
                 maxlength="16" placeholder="16 hex"
                 (input)="onHexInput('joinEui', 16)"
                 (paste)="onHexPaste($event, 'joinEui', 16)" />
        </mat-form-field>
        <div class="adv-err" *ngIf="joinEuiError">
          <mat-icon>error_outline</mat-icon><span>{{ joinEuiError }}</span>
        </div>

      </div>

    </div>

    <!-- ══════════════════════════════════════ -->
    <!-- PASO 3: Resumen                       -->
    <!-- ══════════════════════════════════════ -->
    <div *ngIf="currentStep === 3">
      <div class="adv-card success">
        <div class="adv-card-title"><mat-icon>check_circle</mat-icon>Dispositivo creado</div>
        <div class="adv-success-row">
          <mat-icon>check_circle</mat-icon>
          <span>Creado en ThingsBoard y ChirpStack.</span>
        </div>
        <div class="adv-kv">
          <div class="adv-kv-row">
            <span class="adv-kv-label">Nombre</span>
            <span class="adv-kv-value name">{{ deviceName }}</span>
          </div>
          <div class="adv-kv-row">
            <span class="adv-kv-label">DevEUI</span>
            <span class="adv-kv-value">{{ devEui }}</span>
          </div>
          <div class="adv-kv-row">
            <span class="adv-kv-label">TB Access Token</span>
            <span class="adv-kv-value token">{{ tbAccessToken }}</span>
          </div>
          <div class="adv-kv-row" *ngIf="selectedCustomerTitle">
            <span class="adv-kv-label">Cliente</span>
            <span class="adv-kv-value">{{ selectedCustomerTitle }}</span>
          </div>
        </div>
      </div>
    </div>

  </div><!-- /body -->

  <!-- Actions -->
  <div class="adv-actions">
    <button mat-button class="adv-back" type="button"
            *ngIf="currentStep === 1 || currentStep === 2"
            [disabled]="loading" (click)="prevStep()">
      ← Atrás
    </button>
    <span class="spacer"></span>
    <button mat-button class="adv-cancel" type="button" [disabled]="loading" (click)="cancel()">
      {{ currentStep === 3 ? 'Cerrar' : 'Cancelar' }}
    </button>

    <!-- Step 0: Siguiente (requiere QR o DevEUI) -->
    <button mat-raised-button class="adv-next" type="button"
            *ngIf="currentStep === 0"
            [disabled]="loading || !canProceedFromScan()"
            (click)="proceedFromScan()">
      Siguiente
    </button>

    <!-- Step 1: Siguiente (requiere app + ambos profiles) -->
    <button mat-raised-button class="adv-next" type="button"
            *ngIf="currentStep === 1"
            [disabled]="loading || !canProceedFromConfig() || loadingInit"
            (click)="proceedFromConfig()">
      Siguiente
    </button>

    <!-- Step 2: Crear -->
    <button mat-raised-button class="adv-next" type="button"
            *ngIf="currentStep === 2"
            [disabled]="loading || !canCreate()"
            (click)="createDevice()">
      Crear dispositivo
    </button>

  </div>

</div>
`;

// ── Controller ────────────────────────────────────────────────────────

function AddDeviceController(instance) {
  let vm = instance;

  vm.steps       = ['Escanear', 'Configuración', 'Dispositivo', 'Listo'];
  vm.currentStep = 0;
  vm.loading     = false;
  vm.globalError = '';

  // Step 0 — QR
  vm.cameras          = [];
  vm.selectedCameraIdx = 0;
  vm.qrResult         = null;   // { type, eui, appKey?, sn? }
  vm.nodoData         = null;   // datos del sheet
  vm.loadingNodo      = false;
  vm.qrError          = '';
  vm.manualEui        = '';

  // Step 1 — Config
  vm.applications      = [];
  vm.loadingInit       = true;
  vm.selectedAppId     = '';
  vm.selectedAppName   = '';
  vm.appFilter         = '';
  vm.filteredApps      = [];

  vm.csProfiles        = [];
  vm.selectedCsProfileId = '';
  vm.csProfileFilter   = '';
  vm.filteredCsProfiles = [];

  vm.tbProfiles        = [];
  vm.selectedTbProfileId = '';
  vm.tbProfileFilter   = '';
  vm.filteredTbProfiles = [];

  vm.customers          = [];
  vm.loadingCustomers   = true;
  vm.selectedCustomerId = '';
  vm.selectedCustomerTitle = '';
  vm.customerFilter     = '';
  vm.filteredCustomers  = [];

  // Step 2 — Device
  vm.devEui        = '';
  vm.joinEui       = '';
  vm.joinEuiError  = '';
  vm.appKey        = '';
  vm.appKeyError   = '';
  vm.appKeyFromQR  = false;
  vm.deviceName    = '';
  vm.loadingName   = false;
  vm.editingName   = false;

  // Step 3
  vm.tbAccessToken = '';

  const HEX = /^[0-9a-fA-F]*$/;
  function isHex(s, len) { return s.length === len && HEX.test(s); }

  // ── QR Scanner ─────────────────────────────────────────────────────
  let _stream     = null;
  let _detector   = null;
  let _rafId      = null;

  function stopScanner() {
    if (_rafId)    { cancelAnimationFrame(_rafId); _rafId = null; }
    if (_stream)   { _stream.getTracks().forEach(function(t) { t.stop(); }); _stream = null; }
  }

  function startScanner(deviceId) {
    stopScanner();
    let constraints = { video: deviceId
      ? { deviceId: { exact: deviceId } }
      : { facingMode: 'environment', width: { ideal: 1920 }, height: { ideal: 1080 } }
    };
    navigator.mediaDevices.getUserMedia(constraints)
      .then(function(stream) {
        _stream = stream;
        let video = document.getElementById('adv-qr-video');
        if (!video) return;
        video.srcObject = stream;
        video.play();
        scanLoop(video);
      })
      .catch(function(err) {
        vm.qrError = 'No se pudo acceder a la cámara: ' + err.message;
      });
  }

  function scanLoop(video) {
    if (!_detector) return;
    _rafId = requestAnimationFrame(function() {
      if (!video.readyState || video.readyState < 2) { scanLoop(video); return; }
      _detector.detect(video).then(function(codes) {
        if (codes.length > 0) {
          let raw    = codes[0].rawValue;
          let parsed = parseQR(raw);
          if (parsed.type !== 'desconocido') {
            stopScanner();
            handleQRResult(parsed);
          } else {
            scanLoop(video);
          }
        } else {
          scanLoop(video);
        }
      }).catch(function() { scanLoop(video); });
    });
  }

  function handleQRResult(parsed) {
    vm.qrResult = parsed;
    if (parsed.appKey) {
      vm.appKey       = parsed.appKey;
      vm.appKeyFromQR = true;
    }
    vm.devEui = parsed.eui;
    // Buscar en sheet
    vm.loadingNodo = true;
    fetch(N8N_NODO_URL + '?eui=' + parsed.eui)
      .then(function(r) { return r.json(); })
      .then(function(data) {
        vm.loadingNodo = false;
        if (data.found && data.nodo) {
          vm.nodoData = data.nodo;
        }
      })
      .catch(function() { vm.loadingNodo = false; });
  }

  // Iniciar scanner al abrir
  if (typeof BarcodeDetector !== 'undefined') {
    _detector = new BarcodeDetector({ formats: ['qr_code'] });
    navigator.mediaDevices.enumerateDevices().then(function(devices) {
      vm.cameras = devices.filter(function(d) { return d.kind === 'videoinput'; });
      let backIdx = vm.cameras.findIndex(function(c) {
        return (c.label || '').toLowerCase().includes('back') || (c.label || '').toLowerCase().includes('rear');
      });
      vm.selectedCameraIdx = backIdx >= 0 ? backIdx : 0;
      let cam = vm.cameras[vm.selectedCameraIdx];
      startScanner(cam ? cam.deviceId : null);
    });
  } else {
    vm.qrError = 'Tu navegador no soporta el escáner QR automático. Usá el ingreso manual.';
  }

  vm.switchCamera = function(idx) {
    vm.selectedCameraIdx = idx;
    let cam = vm.cameras[idx];
    if (cam) startScanner(cam.deviceId);
  };

  vm.resetScan = function() {
    vm.qrResult     = null;
    vm.nodoData     = null;
    vm.qrError      = '';
    vm.devEui       = '';
    vm.appKey       = '';
    vm.appKeyFromQR = false;
    // Reiniciar scanner
    setTimeout(function() { startScanner(vm.cameras[vm.selectedCameraIdx] ? vm.cameras[vm.selectedCameraIdx].deviceId : null); }, 100);
  };

  // Ingreso manual
  vm.onManualEuiInput = function() {
    vm.manualEui = vm.manualEui.replace(/[^0-9a-fA-F]/g, '').toUpperCase();
  };
  vm.canManualLookup = function() { return isHex(vm.manualEui, 16); };
  vm.manualLookup = function() {
    if (!vm.canManualLookup()) return;
    let parsed = { type: 'etiqueta', eui: vm.manualEui };
    handleQRResult(parsed);
  };

  vm.canProceedFromScan = function() {
    return (vm.qrResult && !vm.loadingNodo) || isHex(vm.manualEui, 16);
  };

  vm.proceedFromScan = function() {
    // Si hay resultado de QR, ya está seteado; si no, usar manual
    if (!vm.qrResult && isHex(vm.manualEui, 16)) {
      handleQRResult({ type: 'etiqueta', eui: vm.manualEui });
      // esperar el lookup
      let wait = setInterval(function() {
        if (!vm.loadingNodo) {
          clearInterval(wait);
          stopScanner();
          vm.currentStep = 1;
        }
      }, 200);
      return;
    }
    stopScanner();
    vm.currentStep = 1;
  };

  // ── Cargar datos para step 1 ────────────────────────────────────────
  Promise.all([
    csGet('/api/applications?limit=100&tenantId=' + CS_TENANT_ID),
    csGet('/api/device-profiles?limit=100&tenantId=' + CS_TENANT_ID),
    tbGet('/api/deviceProfiles?pageSize=100&page=0')
  ]).then(function(results) {
    vm.applications    = sortByName((results[0] && results[0].result) || []);
    vm.csProfiles      = sortByName((results[1] && results[1].result) || []);
    vm.tbProfiles      = sortByName((results[2] && results[2].data)   || []);
    vm.filteredApps       = vm.applications.slice();
    vm.filteredCsProfiles = vm.csProfiles.slice();
    vm.filteredTbProfiles = vm.tbProfiles.slice();
    vm.loadingInit     = false;
  }).catch(function(err) {
    vm.loadingInit = false;
    vm.globalError = 'Error cargando datos: ' + err.message;
  });

  tbGet('/api/customers?pageSize=100&page=0')
    .then(function(res) {
      vm.customers         = sortByTitle((res && res.data) || []);
      vm.filteredCustomers = vm.customers.slice();
      vm.loadingCustomers  = false;
    })
    .catch(function() { vm.loadingCustomers = false; });

  // ── Sort & filter helpers ────────────────────────────────────────────
  function sortByName(arr) {
    return arr.slice().sort(function(a, b) { return (a.name || '').localeCompare(b.name || '', 'es', {sensitivity: 'base'}); });
  }
  function sortByTitle(arr) {
    return arr.slice().sort(function(a, b) { return (a.title || '').localeCompare(b.title || '', 'es', {sensitivity: 'base'}); });
  }
  function filterBy(arr, key, q) {
    if (!q) return arr.slice();
    let lq = q.toLowerCase();
    return arr.filter(function(x) { return (x[key] || '').toLowerCase().indexOf(lq) !== -1; });
  }

  vm.filterApps       = function() { vm.filteredApps       = filterBy(vm.applications, 'name',  vm.appFilter);       };
  vm.filterCsProfiles = function() { vm.filteredCsProfiles = filterBy(vm.csProfiles,   'name',  vm.csProfileFilter); };
  vm.filterTbProfiles = function() { vm.filteredTbProfiles = filterBy(vm.tbProfiles,   'name',  vm.tbProfileFilter); };
  vm.filterCustomers  = function() { vm.filteredCustomers  = filterBy(vm.customers,    'title', vm.customerFilter);  };

  vm.onAppChange = function() {
    let a = vm.applications.find(function(x) { return x.id === vm.selectedAppId; });
    vm.selectedAppName = a ? a.name : '';
  };
  vm.onTbProfileChange = function() {
    // Cuando selecciona el profile de TB, usamos su nombre para generar el nombre del device
  };
  vm.onCustomerChange = function() {
    let c = vm.customers.find(function(x) { return x.id.id === vm.selectedCustomerId; });
    vm.selectedCustomerTitle = c ? c.title : '';
  };

  vm.canProceedFromConfig = function() {
    return !!vm.selectedAppId && !!vm.selectedCsProfileId && !!vm.selectedTbProfileId;
  };

  vm.proceedFromConfig = function() {
    // Generar nombre basado en modelo del nodo o nombre del TB profile
    let modelo = (vm.nodoData && vm.nodoData['MODELO']) || '';
    if (!modelo) {
      // Usar nombre del TB profile como base
      let tbProf = vm.tbProfiles.find(function(p) { return p.id.id === vm.selectedTbProfileId; });
      modelo = tbProf ? tbProf.name : '';
    }
    vm.loadingName = true;
    vm.currentStep = 2;
    generateDeviceName(modelo).then(function(name) {
      vm.deviceName  = name;
      vm.loadingName = false;
    });
  };

  // ── Hex input ─────────────────────────────────────────────────────
  vm.onHexInput = function(field, len) {
    let v = vm[field].replace(/[^0-9a-fA-F]/g, '').toUpperCase();
    vm[field] = v;
    vm[field + 'Error'] = (v.length > 0 && v.length !== len) ? 'Debe tener ' + len + ' caracteres hex' : '';
  };
  vm.onHexPaste = function($event, field, len) {
    $event.preventDefault();
    let raw = ($event.clipboardData || window.clipboardData).getData('text') || '';
    let v   = raw.replace(/[^0-9a-fA-F]/g, '').toUpperCase().substring(0, len);
    vm[field] = v;
    vm[field + 'Error'] = (v.length > 0 && v.length !== len) ? 'Debe tener ' + len + ' caracteres hex' : '';
  };

  vm.canCreate = function() {
    return vm.deviceName.trim().length > 0
      && !vm.loadingName
      && isHex(vm.devEui, 16)
      && isHex(vm.appKey, 32)
      && !vm.appKeyError
      && (vm.joinEui.length === 0 || isHex(vm.joinEui, 16))
      && !vm.joinEuiError;
  };

  // ── Navegación ───────────────────────────────────────────────────────
  vm.prevStep = function() { vm.currentStep--; vm.globalError = ''; };
  vm.cancel   = function() { stopScanner(); vm.dialogRef.close(null); };

  // ── Crear dispositivo ─────────────────────────────────────────────────
  vm.createDevice = function() {
    vm.loading     = true;
    vm.globalError = '';

    let tbDeviceId = null;
    let tbToken    = null;

    // 1. Crear en TB con device profile
    tbPost('/api/device', {
      name: vm.deviceName.trim(),
      deviceProfileId: { id: vm.selectedTbProfileId, entityType: 'DEVICE_PROFILE' }
    })
    .then(function(tbDev) {
      tbDeviceId = tbDev.id.id;
      return tbGet('/api/device/' + tbDeviceId + '/credentials');
    })
    .then(function(creds) {
      tbToken = creds.credentialsId;
      // 2. Crear en CS
      let payload = {
        device: {
          applicationId:   vm.selectedAppId,
          devEui:          vm.devEui.toLowerCase(),
          name:            vm.deviceName.trim(),
          deviceProfileId: vm.selectedCsProfileId,
          isDisabled:      false,
          variables:       { ThingsBoardAccessToken: tbToken }
        }
      };
      if (isHex(vm.joinEui, 16)) payload.device.joinEui = vm.joinEui.toLowerCase();
      return csPost('/api/devices', payload);
    })
    .then(function() {
      // 3. AppKey en CS
      return csPost('/api/devices/' + vm.devEui.toLowerCase() + '/keys', {
        deviceKeys: {
          devEui: vm.devEui.toLowerCase(),
          nwkKey: vm.appKey.toLowerCase(),
          appKey: vm.appKey.toLowerCase()
        }
      });
    })
    .then(function() {
      // 4. Asignar cliente en TB
      if (vm.selectedCustomerId && tbDeviceId) {
        return tbPost('/api/customer/' + vm.selectedCustomerId + '/device/' + tbDeviceId, {})
          .catch(function() {});
      }
    })
    .then(function() {
      vm.loading       = false;
      vm.tbAccessToken = tbToken;
      vm.currentStep   = 3;
      widgetContext.showSuccessToast('Dispositivo ' + vm.deviceName + ' creado exitosamente');
    })
    .catch(function(err) {
      vm.loading = false;
      let msg = (err.message || '').toLowerCase();
      if (msg.indexOf('already exists') !== -1 || msg.indexOf('duplicate') !== -1 || err.status === 409) {
        vm.globalError = 'Ya existe un dispositivo con este DevEUI en ChirpStack';
      } else {
        vm.globalError = 'Error al crear el dispositivo: ' + err.message;
      }
      // Rollback TB si CS falló
      if (tbDeviceId && vm.currentStep === 2) {
        tbDelete('/api/device/' + tbDeviceId).catch(function() {});
      }
    });
  };
}

// ── Abrir dialog ──────────────────────────────────────────────────────
customDialog.customDialog(htmlTemplate, AddDeviceController).subscribe();

