actionCellButton.customFunction:
// ThingsBoard PE - Widget Editar Dispositivo
// Para: Action cell button en tabla de dispositivos

let $injector = widgetContext.$scope.$injector;
let customDialog = $injector.get(widgetContext.servicesMap.get("customDialog"));
let deviceService = $injector.get(
  widgetContext.servicesMap.get("deviceService"),
);
let attributeService = $injector.get(
  widgetContext.servicesMap.get("attributeService"),
);

openEditDeviceDialog();

function openEditDeviceDialog() {
  customDialog.customDialog(htmlTemplate, EditDeviceController).subscribe();
}

function EditDeviceController(instance) {
  let vm = instance;

  let deviceId = entityId.id;
  vm.loading = true;
  vm.saving = false;
  vm.device = null;

  vm.editDeviceFormGroup = vm.fb.group({
    label: [""],
    inactivityTimeout: [null],
    reportInterval: [null],
  });

  loadDevice();

  let autoAdjust = false;
  let originalReportInterval = null;

  // Al cambiar el intervalo de reporte, ajusta el timeout al triple solo si no supera ya ese valor
  vm.editDeviceFormGroup.get("reportInterval").valueChanges.subscribe(function (val) {
    if (!autoAdjust) return;
    if (val != null && val !== "") {
      let triple = parseInt(val) * 3;
      let currentTimeout = vm.editDeviceFormGroup.get("inactivityTimeout").value;
      if (currentTimeout == null || currentTimeout === "" || parseInt(currentTimeout) <= triple) {
        vm.editDeviceFormGroup.patchValue(
          { inactivityTimeout: triple },
          { emitEvent: false },
        );
        vm.editDeviceFormGroup.get("inactivityTimeout").setErrors(null);
      }
    }
  });

  // Al cambiar el timeout, valida que sea mayor al intervalo de reporte
  vm.editDeviceFormGroup.get("inactivityTimeout").valueChanges.subscribe(function (val) {
    if (!autoAdjust) return;
    let interval = vm.editDeviceFormGroup.get("reportInterval").value;
    let timeoutCtrl = vm.editDeviceFormGroup.get("inactivityTimeout");
    if (val != null && interval != null && val !== "" && interval !== "") {
      if (parseInt(val) <= parseInt(interval)) {
        timeoutCtrl.setErrors({ inactivityTooLow: true });
      } else {
        timeoutCtrl.setErrors(null);
      }
    }
  });

  vm.cancel = function () {
    vm.dialogRef.close(null);
  };

  vm.save = function () {
    vm.editDeviceFormGroup.markAsPristine();
    vm.saving = true;

    let formValue = vm.editDeviceFormGroup.value;
    vm.device.label = formValue.label;

    let entity = { id: deviceId, entityType: "DEVICE" };

    function finish(savedDevice) {
      vm.saving = false;
      widgetContext.showSuccessToast("Dispositivo actualizado");
      widgetContext.updateAliases();
      vm.dialogRef.close(savedDevice);
    }

    function saveShared(savedDevice) {
      let sharedAttrs = [];

      let interval = formValue.reportInterval;
      if (interval != null && interval !== "" &&
          parseInt(interval) !== originalReportInterval) {
        sharedAttrs.push({ key: "report_interval", value: parseInt(interval) });
      }

      if (sharedAttrs.length > 0) {
        attributeService
          .saveEntityAttributes(entity, "SHARED_SCOPE", sharedAttrs)
          .subscribe(
            function () { finish(savedDevice); },
            function (error) {
              vm.saving = false;
              widgetContext.showErrorToast(
                "Error guardando atributos: " +
                  (error.message || JSON.stringify(error)),
              );
            },
          );
      } else {
        finish(savedDevice);
      }
    }

    deviceService.saveDevice(vm.device).subscribe(
      function (savedDevice) {
        let timeoutMinutes = formValue.inactivityTimeout;
        if (timeoutMinutes != null && timeoutMinutes !== "") {
          let timeoutMs = Math.round(timeoutMinutes * 60 * 1000);
          attributeService
            .saveEntityAttributes(entity, "SERVER_SCOPE", [
              { key: "inactivityTimeout", value: timeoutMs },
            ])
            .subscribe(
              function () { saveShared(savedDevice); },
              function (error) {
                vm.saving = false;
                widgetContext.showErrorToast(
                  "Error guardando timeout: " +
                    (error.message || JSON.stringify(error)),
                );
              },
            );
        } else {
          saveShared(savedDevice);
        }
      },
      function (error) {
        vm.saving = false;
        widgetContext.showErrorToast(
          "Error: " + (error.message || JSON.stringify(error)),
        );
        console.error("Error guardando dispositivo:", error);
      },
    );
  };

  function loadDevice() {
    deviceService.getDevice(deviceId).subscribe(
      function (device) {
        vm.device = device;
        vm.editDeviceFormGroup.patchValue({
          label: device.label || "",
        });

        let entity = { id: deviceId, entityType: "DEVICE" };

        attributeService
          .getEntityAttributes(entity, "SERVER_SCOPE", ["inactivityTimeout"])
          .subscribe(
            function (attrs) {
              if (attrs && attrs.length > 0) {
                let timeoutMs = attrs[0].value;
                vm.editDeviceFormGroup.patchValue({
                  inactivityTimeout: Math.round(timeoutMs / 60000),
                });
              }

              attributeService
                .getEntityAttributes(entity, "SHARED_SCOPE", ["report_interval"])
                .subscribe(
                  function (sharedAttrs) {
                    if (sharedAttrs && sharedAttrs.length > 0) {
                      sharedAttrs.forEach(function (a) {
                        if (a.key === "report_interval") {
                          originalReportInterval = a.value;
                          vm.editDeviceFormGroup.patchValue({ reportInterval: a.value });
                        }
                      });
                    }
                    vm.loading = false;
                    autoAdjust = true;
                  },
                  function () {
                    vm.loading = false;
                    autoAdjust = true;
                  },
                );
            },
            function () {
              vm.loading = false;
              autoAdjust = true;
            },
          );
      },
      function (error) {
        vm.loading = false;
        widgetContext.showErrorToast("Error cargando dispositivo");
        console.error("Error cargando dispositivo:", error);
      },
    );
  }
}

