actionCellButton.customFunction:
// ThingsBoard PE - Widget Configuración de Dispositivo
// Para: Action cell button en tabla de dispositivos
// Dispatch por device.type. Cada tipo expone sus parámetros operativos.

let $injector = widgetContext.$scope.$injector;
let customDialog = $injector.get(widgetContext.servicesMap.get("customDialog"));
let deviceService = $injector.get(
  widgetContext.servicesMap.get("deviceService"),
);
let attributeService = $injector.get(
  widgetContext.servicesMap.get("attributeService"),
);

const RDL_TYPES = ["EM410-RDL", "EM411-RDL","EM410-RDL-TEST"];

openConfigDeviceDialog();

function openConfigDeviceDialog() {
  customDialog.customDialog(htmlTemplate, ConfigDeviceController).subscribe();
}

function ConfigDeviceController(instance) {
  let vm = instance;
  let deviceId = entityId.id;
  vm.loading = true;
  vm.saving = false;
  vm.device = null;
  vm.deviceType = null;
  vm.deviceLabel = null;
  vm.isRdl = false;
  vm.unsupported = false;

  vm.peakSortingOptions = [
    { value: "closest", label: "Pico cercano" },
    { value: "strongest", label: "Pico más fuerte" },
  ];
  vm.distanceModeOptions = [
    { value: "general", label: "General" },
    { value: "rainwater", label: "Rainwater" },
    { value: "wastewater", label: "Wastewater" },
    { value: "tank", label: "Tank" },
  ];
  vm.volumeUnitOptions = [
    { value: "L", label: "Litros" },
    { value: "m3", label: "Metros cúbicos (m³)" },
  ];
  vm.tankTypeOptions = [
    { value: "linear", label: "Lineal (volumen máximo)" },
    { value: "h_cylinder", label: "Cilíndrico horizontal" },
    { value: "v_cylinder_cone", label: "Cilíndrico vertical con fondo cónico" },
    { value: "strapping", label: "Tabla de calibración" },
  ];

  vm.configFormGroup = vm.fb.group({
    peakSorting: ["strongest"],
    signalQuality: [15],
    distanceMode: ["general"],
    measurementRange: [12],
    thresholdSensitivity: [0.5],
    distanceCalibrationEnable: [false],
    distanceCalibrationValue: [0],
    sendPeakSorting: [false],
    sendSignalQuality: [false],
    sendDistanceMode: [false],
    sendMeasurementRange: [false],
    sendThresholdSensitivity: [false],
    sendDistanceCalibration: [false],
    distanceMin: [null],
    distanceMax: [null],
    enableLevel: [true],
    enableDepth: [false],
    depthUnit: ["m"],
    enableVolume: [false],
    volumeUnit: ["L"],
    tankType: [null],
    tankDiameter: [null],
    tankLength: [null],
    tankConeHeight: [null],
    tankCapacity: [null],
  });

  vm.CAPACITY_TOLERANCE = 0.10;

  vm.strappingRows = [];

  let originalPeakSorting = null;
  let originalSignalQuality = null;
  let originalDistanceMode = null;
  let originalMeasurementRange = null;
  let originalThresholdSensitivity = null;
  let originalDistanceCalibration = null;
  let originalDistanceMin = null;
  let originalDistanceMax = null;
  let originalEnabledMetrics = null;

  vm._autoCheckEnabled = false;

  function setupAutoCheck(field, sendField) {
    vm.configFormGroup.get(field).valueChanges.subscribe(function () {
      if (!vm._autoCheckEnabled) return;
      vm.configFormGroup.patchValue({ [sendField]: true });
    });
  }
  setupAutoCheck("peakSorting", "sendPeakSorting");
  setupAutoCheck("signalQuality", "sendSignalQuality");
  setupAutoCheck("distanceMode", "sendDistanceMode");
  setupAutoCheck("measurementRange", "sendMeasurementRange");
  setupAutoCheck("thresholdSensitivity", "sendThresholdSensitivity");
  setupAutoCheck("distanceCalibrationEnable", "sendDistanceCalibration");
  setupAutoCheck("distanceCalibrationValue", "sendDistanceCalibration");

  vm.configFormGroup.get("signalQuality").valueChanges.subscribe(function (val) {
    let ctrl = vm.configFormGroup.get("signalQuality");
    if (val == null || val === "") {
      ctrl.setErrors(null);
      return;
    }
    let n = parseInt(val);
    if (isNaN(n) || n < -10 || n > 35) {
      ctrl.setErrors({ outOfRange: true });
    } else {
      ctrl.setErrors(null);
    }
  });

  function validateMinMax() {
    let minCtrl = vm.configFormGroup.get("distanceMin");
    let maxCtrl = vm.configFormGroup.get("distanceMax");
    let min = minCtrl.value;
    let max = maxCtrl.value;
    if (min == null || max == null || min === "" || max === "") {
      minCtrl.setErrors(null);
      return;
    }
    if (parseFloat(min) <= parseFloat(max)) {
      minCtrl.setErrors({ minNotGreater: true });
    } else {
      minCtrl.setErrors(null);
    }
  }

  vm.configFormGroup.get("distanceMin").valueChanges.subscribe(function () {
    validateMinMax();
    validateTankFit();
    validateCapacityFit();
  });
  vm.configFormGroup.get("distanceMax").valueChanges.subscribe(function () {
    validateMinMax();
    validateTankFit();
    validateCapacityFit();
  });
  vm.configFormGroup.get("tankDiameter").valueChanges.subscribe(function () {
    validateTankFit();
    validateCapacityFit();
  });
  vm.configFormGroup.get("tankType").valueChanges.subscribe(function () {
    validateTankFit();
    validateCapacityFit();
  });
  vm.configFormGroup.get("tankLength").valueChanges.subscribe(validateCapacityFit);
  vm.configFormGroup.get("tankConeHeight").valueChanges.subscribe(validateCapacityFit);
  vm.configFormGroup.get("tankCapacity").valueChanges.subscribe(validateCapacityFit);
  vm.configFormGroup.get("volumeUnit").valueChanges.subscribe(validateCapacityFit);
  vm.configFormGroup.get("enableVolume").valueChanges.subscribe(validateCapacityFit);

  function computeGeomCapacityM3() {
    let f = vm.configFormGroup.value;
    if (!f.tankType) return null;
    let dMin = parseFloat(f.distanceMin);
    let dMax = parseFloat(f.distanceMax);

    if (f.tankType === "h_cylinder") {
      let D = parseFloat(f.tankDiameter);
      let L = parseFloat(f.tankLength);
      if (isNaN(D) || isNaN(L)) return null;
      return Math.PI * (D / 2) * (D / 2) * L;
    }
    if (f.tankType === "v_cylinder_cone") {
      let D = parseFloat(f.tankDiameter);
      let hCone = parseFloat(f.tankConeHeight);
      if (isNaN(D) || isNaN(hCone) || isNaN(dMin) || isNaN(dMax) || dMin <= dMax) return null;
      let r = D / 2;
      let h_total = dMin - dMax;
      return (Math.PI / 3) * r * r * hCone + Math.PI * r * r * h_total;
    }
    if (f.tankType === "strapping") {
      if (vm.strappingRows.length === 0) return null;
      let last = vm.strappingRows[vm.strappingRows.length - 1];
      if (last.v == null || last.v === "") return null;
      return parseFloat(last.v) / 1000.0;
    }
    return null;
  }

  function validateCapacityFit() {
    vm.capacityWarning = null;
    let f = vm.configFormGroup.value;
    if (!f.enableVolume) return;
    if (f.tankType === "linear") return;
    let cap = parseFloat(f.tankCapacity);
    if (isNaN(cap)) return;
    let geom_m3 = computeGeomCapacityM3();
    if (geom_m3 == null) return;
    let geom = (f.volumeUnit === "m3") ? geom_m3 : geom_m3 * 1000;
    let diff = Math.abs(geom - cap) / geom;
    if (diff > vm.CAPACITY_TOLERANCE) {
      vm.capacityWarning = {
        computed: geom,
        entered: cap,
        diffPct: diff * 100,
      };
    }
  }

  function deriveCapacityFromTank(tank, unit, dMin, dMax) {
    if (!tank || !tank.type) return null;
    let cap_m3 = null;
    if (tank.type === "linear") {
      if (tank.volume_max == null) return null;
      cap_m3 = tank.volume_max / 1000.0;
    } else if (tank.type === "h_cylinder") {
      if (tank.diameter == null || tank.length == null) return null;
      cap_m3 = Math.PI * (tank.diameter / 2) * (tank.diameter / 2) * tank.length;
    } else if (tank.type === "v_cylinder_cone") {
      if (tank.diameter == null || tank.cone_height == null || dMin == null || dMax == null) return null;
      let r = tank.diameter / 2;
      let h_total = parseFloat(dMin) - parseFloat(dMax);
      if (h_total <= 0) return null;
      cap_m3 = (Math.PI / 3) * r * r * tank.cone_height + Math.PI * r * r * h_total;
    } else if (tank.type === "strapping") {
      if (!Array.isArray(tank.table) || tank.table.length === 0) return null;
      let lastV = tank.table[tank.table.length - 1][1];
      cap_m3 = lastV / 1000.0;
    }
    if (cap_m3 == null) return null;
    return (unit === "m3") ? cap_m3 : cap_m3 * 1000;
  }

  function validateTankFit() {
    let ctrl = vm.configFormGroup.get("tankDiameter");
    let type = vm.configFormGroup.get("tankType").value;
    if (type !== "h_cylinder") {
      ctrl.setErrors(null);
      return;
    }
    let D = vm.configFormGroup.get("tankDiameter").value;
    let dMin = vm.configFormGroup.get("distanceMin").value;
    let dMax = vm.configFormGroup.get("distanceMax").value;
    if (D == null || D === "" || dMin == null || dMin === "" || dMax == null || dMax === "") {
      ctrl.setErrors(null);
      return;
    }
    let hTotal = parseFloat(dMin) - parseFloat(dMax);
    if (hTotal < parseFloat(D)) {
      ctrl.setErrors({ cylinderTooTall: true });
    } else {
      ctrl.setErrors(null);
    }
  }

  vm.addStrappingRow = function () {
    vm.strappingRows.push({ h: null, v: null });
    validateCapacityFit();
  };

  vm.removeStrappingRow = function (idx) {
    vm.strappingRows.splice(idx, 1);
    validateCapacityFit();
  };

  vm.onStrappingRowChange = function () {
    validateCapacityFit();
  };

  vm.strappingValid = function () {
    if (vm.strappingRows.length < 2) return false;
    let prevH = -Infinity;
    for (let i = 0; i < vm.strappingRows.length; i++) {
      let r = vm.strappingRows[i];
      if (r.h == null || r.h === "" || r.v == null || r.v === "") return false;
      let h = parseFloat(r.h);
      let v = parseFloat(r.v);
      if (isNaN(h) || isNaN(v) || v < 0) return false;
      if (h <= prevH) return false;
      prevH = h;
    }
    return true;
  };

  vm.anyMetricOn = function () {
    let f = vm.configFormGroup.value;
    return !!(f.enableLevel || f.enableDepth || f.enableVolume);
  };

  vm.computedCapacity = function () {
    let geom_m3 = computeGeomCapacityM3();
    if (geom_m3 == null) return null;
    let unit = vm.configFormGroup.get("volumeUnit").value;
    return (unit === "m3") ? geom_m3 : geom_m3 * 1000;
  };

  vm.formInvalid = function () {
    if (vm.configFormGroup.invalid) return true;
    let f = vm.configFormGroup.value;
    if (!vm.anyMetricOn()) return false;
    if (f.distanceMin == null || f.distanceMin === "") return true;
    if (f.distanceMax == null || f.distanceMax === "") return true;
    if (!f.tankType) return true;
    if (!f.enableVolume) return false;
    if (f.tankCapacity == null || f.tankCapacity === "") return true;
    if (f.tankType === "h_cylinder" &&
        ((f.tankDiameter == null || f.tankDiameter === "") ||
         (f.tankLength == null || f.tankLength === ""))) return true;
    if (f.tankType === "v_cylinder_cone" &&
        ((f.tankDiameter == null || f.tankDiameter === "") ||
         (f.tankConeHeight == null || f.tankConeHeight === ""))) return true;
    if (f.tankType === "strapping" && !vm.strappingValid()) return true;
    return false;
  };

  vm.cancel = function () {
    vm.dialogRef.close(null);
  };

  vm.save = function () {
    if (vm.formInvalid()) return;
    vm.saving = true;

    let entity = { id: deviceId, entityType: "DEVICE" };
    let formValue = vm.configFormGroup.value;

    function finish() {
      vm.saving = false;
      widgetContext.showSuccessToast("Configuración actualizada");
      vm.dialogRef.close(true);
    }

    function fail(msg) {
      return function (error) {
        vm.saving = false;
        widgetContext.showErrorToast(
          msg + ": " + (error.message || JSON.stringify(error)),
        );
      };
    }

    function saveShared(cb) {
      let sharedAttrs = [];
      if (formValue.sendPeakSorting &&
          formValue.peakSorting != null && formValue.peakSorting !== "") {
        sharedAttrs.push({ key: "peak_sorting", value: formValue.peakSorting });
      }
      if (formValue.sendSignalQuality &&
          formValue.signalQuality != null && formValue.signalQuality !== "") {
        sharedAttrs.push({ key: "signal_quality", value: parseInt(formValue.signalQuality) });
      }
      if (formValue.sendDistanceMode &&
          formValue.distanceMode != null && formValue.distanceMode !== "") {
        sharedAttrs.push({ key: "distance_mode", value: formValue.distanceMode });
      }
      if (formValue.sendMeasurementRange &&
          formValue.measurementRange != null && formValue.measurementRange !== "") {
        sharedAttrs.push({
          key: "distance_range",
          value: {
            mode: formValue.distanceMode || "general",
            max: Math.round(parseFloat(formValue.measurementRange) * 1000),
          },
        });
      }
      if (formValue.sendThresholdSensitivity &&
          formValue.thresholdSensitivity != null && formValue.thresholdSensitivity !== "") {
        sharedAttrs.push({ key: "distance_threshold_sensitive", value: parseFloat(formValue.thresholdSensitivity) });
      }
      if (formValue.sendDistanceCalibration) {
        sharedAttrs.push({
          key: "distance_calibration_settings",
          value: {
            enable: formValue.distanceCalibrationEnable ? "enable" : "disable",
            calibration_value: parseInt(formValue.distanceCalibrationValue) || 0,
          },
        });
      }
      if (sharedAttrs.length === 0) return cb();
      attributeService
        .saveEntityAttributes(entity, "SHARED_SCOPE", sharedAttrs)
        .subscribe(cb, fail("Error guardando atributos de medición"));
    }

    function saveServer(cb) {
      let serverAttrs = [];
      if (formValue.distanceMin != null && formValue.distanceMin !== "") {
        serverAttrs.push({ key: "distance_min", value: parseFloat(formValue.distanceMin) });
      }
      if (formValue.distanceMax != null && formValue.distanceMax !== "") {
        serverAttrs.push({ key: "distance_max", value: parseFloat(formValue.distanceMax) });
      }

      serverAttrs.push({ key: "enable_level",  value: !!formValue.enableLevel });
      serverAttrs.push({ key: "enable_depth",  value: !!formValue.enableDepth });
      serverAttrs.push({ key: "enable_volume", value: !!formValue.enableVolume });

      if (formValue.tankType) {
        serverAttrs.push({ key: "tank_type", value: formValue.tankType });
      }

      if (formValue.enableDepth) {
        serverAttrs.push({ key: "unit_depth", value: formValue.depthUnit || "m" });
      }

      if (formValue.enableVolume) {
        let unit = formValue.volumeUnit || "L";
        let cap = parseFloat(formValue.tankCapacity);
        serverAttrs.push({ key: "unit_volume", value: unit });
        serverAttrs.push({ key: "volume_max", value: cap });
      }

      if (vm.anyMetricOn()) {
        let tank = {};
        if (formValue.tankType) {
          tank.type = formValue.tankType;
          if (formValue.tankType === "h_cylinder") {
            if (formValue.tankDiameter != null && formValue.tankDiameter !== "") {
              tank.diameter = parseFloat(formValue.tankDiameter);
            }
            if (formValue.tankLength != null && formValue.tankLength !== "") {
              tank.length = parseFloat(formValue.tankLength);
            }
          } else if (formValue.tankType === "v_cylinder_cone") {
            if (formValue.tankDiameter != null && formValue.tankDiameter !== "") {
              tank.diameter = parseFloat(formValue.tankDiameter);
            }
            if (formValue.tankConeHeight != null && formValue.tankConeHeight !== "") {
              tank.cone_height = parseFloat(formValue.tankConeHeight);
            }
          } else if (formValue.tankType === "strapping" && vm.strappingRows.length > 0) {
            tank.table = vm.strappingRows.map(function (r) {
              return [parseFloat(r.h), parseFloat(r.v)];
            });
          }
          if (formValue.enableVolume) {
            let cap2 = parseFloat(formValue.tankCapacity);
            let cap_l = (formValue.volumeUnit === "m3") ? cap2 * 1000 : cap2;
            tank.volume_max = cap_l;
          }
        }
        serverAttrs.push({ key: "tank_config", value: JSON.stringify(tank) });
      }

      attributeService
        .saveEntityAttributes(entity, "SERVER_SCOPE", serverAttrs)
        .subscribe(cb, fail("Error guardando configuración"));
    }

    saveServer(function () {
      saveShared(finish);
    });
  };

  loadDevice();

  function loadDevice() {
    deviceService.getDevice(deviceId).subscribe(
      function (device) {
        vm.device = device;
        vm.deviceType = device.type;
        vm.deviceLabel = device.label
        vm.isRdl = RDL_TYPES.indexOf(device.type) !== -1;
        if (!vm.isRdl) {
          vm.unsupported = true;
          vm.loading = false;
          return;
        }
        loadRdlAttrs();
      },
      function (error) {
        vm.loading = false;
        widgetContext.showErrorToast("Error cargando dispositivo");
        console.error("Error cargando dispositivo:", error);
      },
    );
  }

  function initSendChecks() {
    vm.configFormGroup.patchValue({
      sendPeakSorting: originalPeakSorting == null,
      sendSignalQuality: originalSignalQuality == null,
      sendDistanceMode: originalDistanceMode == null,
      sendMeasurementRange: originalMeasurementRange == null,
      sendThresholdSensitivity: originalThresholdSensitivity == null,
      sendDistanceCalibration: originalDistanceCalibration == null,
    });
    vm._autoCheckEnabled = true;
  }

  function loadRdlAttrs() {
    let entity = { id: deviceId, entityType: "DEVICE" };
    let sharedKeys = [
      "peak_sorting", "signal_quality", "distance_mode",
      "distance_range", "distance_threshold_sensitive",
      "distance_calibration_settings",
    ];
    let serverKeys = [
      "distance_min", "distance_max",
      "enable_level", "enable_depth", "unit_depth",
      "enable_volume", "unit_volume", "tank_type", "volume_max", "tank_config",
      "enabled_metrics", "volume_unit",
    ];

    attributeService.getEntityAttributes(entity, "SHARED_SCOPE", sharedKeys).subscribe(
      function (sharedAttrs) {
        if (sharedAttrs) {
          sharedAttrs.forEach(function (a) {
            if (a.key === "peak_sorting") {
              originalPeakSorting = a.value;
              vm.configFormGroup.patchValue({ peakSorting: a.value });
            } else if (a.key === "signal_quality") {
              originalSignalQuality = a.value;
              vm.configFormGroup.patchValue({ signalQuality: a.value });
            } else if (a.key === "distance_mode") {
              originalDistanceMode = a.value;
              vm.configFormGroup.patchValue({ distanceMode: a.value });
            } else if (a.key === "distance_range") {
              let raw = a.value;
              let parsed = null;
              try {
                parsed = typeof raw === "string" ? JSON.parse(raw) : raw;
              } catch (e) {
                console.error("distance_range inválido:", e);
              }
              if (parsed && parsed.max != null) {
                let m = parsed.max / 1000.0;
                originalMeasurementRange = m;
                vm.configFormGroup.patchValue({ measurementRange: m });
              }
            } else if (a.key === "distance_threshold_sensitive") {
              originalThresholdSensitivity = a.value;
              vm.configFormGroup.patchValue({ thresholdSensitivity: a.value });
            } else if (a.key === "distance_calibration_settings") {
              let raw = a.value;
              let parsed = null;
              try {
                parsed = typeof raw === "string" ? JSON.parse(raw) : raw;
              } catch (e) {
                console.error("distance_calibration_settings inválido:", e);
              }
              if (parsed) {
                originalDistanceCalibration = parsed;
                vm.configFormGroup.patchValue({
                  distanceCalibrationEnable: parsed.enable === "enable",
                  distanceCalibrationValue: parsed.calibration_value != null ? parsed.calibration_value : 0,
                });
              }
            }
          });
        }
        attributeService.getEntityAttributes(entity, "SERVER_SCOPE", serverKeys).subscribe(
          function (serverAttrs) {
            let flat = {
              hasFlag: false,
              enableLevel: null,
              enableDepth: null,
              enableVolume: null,
              unitDepth: null,
              unitVolume: null,
              tankType: null,
              volumeMax: null,
            };
            let tankConfigRaw = null;
            let enabledMetricsRaw = null;
            let legacyVolumeUnit = null;

            if (serverAttrs) {
              serverAttrs.forEach(function (a) {
                if (a.key === "distance_min") {
                  originalDistanceMin = a.value;
                  vm.configFormGroup.patchValue({ distanceMin: a.value });
                } else if (a.key === "distance_max") {
                  originalDistanceMax = a.value;
                  vm.configFormGroup.patchValue({ distanceMax: a.value });
                } else if (a.key === "enable_level") {
                  flat.hasFlag = true; flat.enableLevel = !!a.value;
                } else if (a.key === "enable_depth") {
                  flat.hasFlag = true; flat.enableDepth = !!a.value;
                } else if (a.key === "enable_volume") {
                  flat.hasFlag = true; flat.enableVolume = !!a.value;
                } else if (a.key === "unit_depth") {
                  flat.unitDepth = a.value;
                } else if (a.key === "unit_volume") {
                  flat.unitVolume = a.value;
                } else if (a.key === "tank_type") {
                  flat.tankType = a.value;
                } else if (a.key === "volume_max") {
                  flat.volumeMax = a.value;
                } else if (a.key === "tank_config") {
                  tankConfigRaw = a.value;
                } else if (a.key === "enabled_metrics") {
                  enabledMetricsRaw = a.value;
                  originalEnabledMetrics = a.value;
                } else if (a.key === "volume_unit") {
                  legacyVolumeUnit = a.value;
                }
              });
            }

            if (flat.hasFlag) {
              applyFlatAttrs(flat, tankConfigRaw);
            } else if (enabledMetricsRaw != null) {
              applyEnabledMetrics(enabledMetricsRaw);
            } else if (tankConfigRaw != null) {
              applyLegacyTankConfig(tankConfigRaw, legacyVolumeUnit);
            }
            initSendChecks();
            vm.loading = false;
          },
          function () { vm.loading = false; },
        );
      },
      function () { vm.loading = false; },
    );
  }

  function applyFlatAttrs(flat, tankConfigRaw) {
    vm.configFormGroup.patchValue({
      enableLevel: !!flat.enableLevel,
      enableDepth: !!flat.enableDepth,
      enableVolume: !!flat.enableVolume,
    });
    if (flat.unitDepth) {
      vm.configFormGroup.patchValue({ depthUnit: flat.unitDepth });
    }
    if (flat.unitVolume) {
      vm.configFormGroup.patchValue({ volumeUnit: flat.unitVolume });
    }
    if (flat.volumeMax != null) {
      vm.configFormGroup.patchValue({ tankCapacity: flat.volumeMax });
    }
    if (flat.tankType) {
      vm.configFormGroup.patchValue({ tankType: flat.tankType });
    }
    if (flat.enableVolume && tankConfigRaw != null) {
      let cfg;
      try {
        cfg = typeof tankConfigRaw === "string" ? JSON.parse(tankConfigRaw) : tankConfigRaw;
      } catch (e) {
        console.error("tank_config inválido:", e);
        return;
      }
      applyTankShape(cfg);
    }
  }

  function applyEnabledMetrics(raw) {
    let cfg;
    try {
      cfg = typeof raw === "string" ? JSON.parse(raw) : raw;
    } catch (e) {
      console.error("enabled_metrics inválido:", e);
      return;
    }
    if (!cfg || typeof cfg !== "object") return;

    vm.configFormGroup.patchValue({
      enableLevel: cfg.level != null,
      enableDepth: cfg.depth != null,
      enableVolume: cfg.volume != null,
    });

    if (cfg.depth && cfg.depth.unit) {
      vm.configFormGroup.patchValue({ depthUnit: cfg.depth.unit });
    }

    if (cfg.volume) {
      let unit = cfg.volume.unit || "L";
      if (cfg.volume.unit) {
        vm.configFormGroup.patchValue({ volumeUnit: cfg.volume.unit });
      }
      if (cfg.volume.tank) {
        applyTankShape(cfg.volume.tank);
        prefillCapacity(cfg.volume.tank, unit);
      }
    }
  }

  function applyLegacyTankConfig(raw, legacyUnit) {
    let cfg;
    try {
      cfg = typeof raw === "string" ? JSON.parse(raw) : raw;
    } catch (e) {
      console.error("tank_config inválido:", e);
      return;
    }
    if (!cfg || !cfg.type) return;
    let unit = legacyUnit || "L";
    vm.configFormGroup.patchValue({
      enableLevel: true,
      enableVolume: true,
      volumeUnit: unit,
    });
    applyTankShape(cfg);
    prefillCapacity(cfg, unit);
  }

  function applyTankShape(tank) {
    if (!tank || !tank.type) return;
    vm.configFormGroup.patchValue({ tankType: tank.type });
    if (tank.type === "h_cylinder") {
      vm.configFormGroup.patchValue({
        tankDiameter: tank.diameter,
        tankLength: tank.length,
      });
    } else if (tank.type === "v_cylinder_cone") {
      vm.configFormGroup.patchValue({
        tankDiameter: tank.diameter,
        tankConeHeight: tank.cone_height,
      });
    } else if (tank.type === "strapping" && Array.isArray(tank.table)) {
      vm.strappingRows = tank.table.map(function (pair) {
        return { h: pair[0], v: pair[1] };
      });
    }
  }

  function prefillCapacity(tank, unit) {
    let cap = deriveCapacityFromTank(
      tank, unit,
      vm.configFormGroup.get("distanceMin").value,
      vm.configFormGroup.get("distanceMax").value,
    );
    if (cap != null) {
      vm.configFormGroup.patchValue({ tankCapacity: cap });
    }
  }
}

actionCellButton.showWidgetActionFunction:
// Show action function — Configuración de dispositivo
// Oculta este action para devices con type "UC501".
// data: fila de la tabla; trae los campos del device, entre ellos `type`.

if (data && data.type === "UC501") {
  return true;
}
return false;

actionCellButton.customCss:
.cdk-overlay-pane {
  max-width: 95vw !important;
  max-height: 95vh !important;
}

.config-dialog {
  font-family: "Roboto", Arial, sans-serif;
  width: 620px;
  max-height: 90vh;
  border-radius: 8px;
  overflow: hidden;
  display: flex;
  flex-direction: column;
}

@media (max-width: 600px) {
  .config-dialog {
    width: 100%;
    max-height: 100vh;
  }
}

/* ── Header ── */
.config-dialog .dialog-header {
  background: #24272a;
  padding: 16px 20px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  flex-shrink: 0;
}

.config-dialog .dialog-header h2 {
  margin: 0;
  font-size: 18px;
  font-weight: 500;
  color: #ffffff;
  letter-spacing: 0.3px;
}

.config-dialog .dialog-header .close-btn {
  color: #ffffff !important;
  opacity: 0.85;
  transition: opacity 0.2s ease;
}

.config-dialog .dialog-header .close-btn:hover {
  opacity: 1;
}

/* ── Progress ── */
.config-dialog .progress-bar {
  height: 3px;
  flex-shrink: 0;
}

.config-dialog .progress-spacer {
  height: 3px;
  flex-shrink: 0;
}

/* ── Body ── */
.config-dialog .dialog-body {
  padding: 20px 20px 12px;
  background: #f7f8fa;
  display: flex;
  flex-direction: column;
  gap: 14px;
  overflow-y: auto;
  flex: 1 1 auto;
  min-height: 0;
}

.config-dialog .loading-container {
  text-align: center;
  padding: 30px 0;
}

.config-dialog .loading-container p {
  color: #888;
  font-size: 14px;
  margin: 0;
}

/* ── Form card ── */
.config-dialog .form-card {
  background: #ffffff;
  border-radius: 8px;
  padding: 18px 16px 14px;
  border-left: 4px solid #ee7623;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.06);
}

.config-dialog .form-card .mat-form-field {
  width: 100%;
}

.config-dialog .form-card .mat-form-field + .mat-form-field {
  margin-top: 16px;
}

/* ── Shared field row: grid checkbox | input ── */
.config-dialog .shared-field-row {
  display: grid;
  grid-template-columns: 24px 1fr;
  gap: 10px;
  align-items: start;
}

.config-dialog .shared-field-row + .shared-field-row {
  margin-top: 16px;
}

.config-dialog .shared-field-row .mat-form-field {
  width: 100%;
  min-width: 0;
  margin-top: 0 !important;
}

.config-dialog .shared-field-send {
  margin-top: 20px;
  line-height: 1;
}

.config-dialog .shared-field-send .mat-checkbox-layout {
  margin: 0;
  padding: 0;
  width: 18px;
}

.config-dialog .shared-field-send .mat-checkbox-inner-container {
  margin: 0;
}

.config-dialog .shared-field-send .mat-checkbox-label {
  display: none;
}

.config-dialog .shared-field-send.mat-checkbox-checked .mat-checkbox-frame,
.config-dialog .shared-field-send.mat-checkbox-checked .mat-checkbox-background {
  border-color: #ee7623 !important;
