}

/* ── Calibración de distancia (compound) ── */
.config-dialog .distance-cal-group {
  display: flex;
  flex-direction: column;
  gap: 10px;
}

.config-dialog .distance-cal-toggle {
  font-size: 13px;
  color: #333;
}

.config-dialog .distance-cal-toggle.mat-checked .mat-slide-toggle-bar {
  background-color: rgba(238, 118, 35, 0.5) !important;
}

.config-dialog .distance-cal-toggle.mat-checked .mat-slide-toggle-thumb {
  background-color: #ee7623 !important;
}

/* Indicador visual: borde naranja en el input cuando el checkbox está activo */
.config-dialog .shared-field-row:has(.mat-checkbox-checked) .mat-form-field-flex {
  background: linear-gradient(to right, rgba(238, 118, 35, 0.06), transparent 60%);
  border-radius: 4px;
}

/* ── Section header ── */
.config-dialog .section-header {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-bottom: 4px;
}

.config-dialog .section-icon {
  font-size: 20px;
  width: 20px;
  height: 20px;
  color: #ee7623;
}

.config-dialog .section-title {
  font-size: 14px;
  font-weight: 600;
  color: #333;
  letter-spacing: 0.3px;
  text-transform: uppercase;
}

.config-dialog .section-description {
  margin: 0 0 12px;
